SELECT n.id, n.title, LEFT(n.content, 100) as summary, n.notice_type as noticeType, n.priority, n.publisher_id as publisherId, n.publisher_name as publisherName, n.publish_time as publishTime, n.expire_time as expireTime, COALESCE(nr.read_status, 0) as readStatus, nr.read_at as readAt FROM notice n LEFT JOIN notice_scope ns ON n.id = ns.notice_id LEFT JOIN notice_read nr ON n.id = nr.notice_id AND nr.user_id = #{userId} WHERE n.is_deleted = 0
AND n.status = 'PUBLISHED' AND n.publish_time <= NOW() AND (n.expire_time IS NULL OR n.expire_time >= NOW())
AND (n.title LIKE CONCAT('%', #{dto.keyword}, '%') OR n.content LIKE CONCAT('%', #{dto.keyword}, '%'))
AND n.notice_type = #{dto.noticeType}
AND n.priority = #{dto.priority}
AND COALESCE(nr.read_status, 0) = #{dto.readStatus}
AND ( ns.scope_type = 'ALL' OR ns.scope_type = 'USER' AND ns.scope_id = #{userId} OR ns.scope_type = 'DEPT' AND ns.scope_id = #{deptId} ) GROUP BY n.id ORDER BY n.publish_time DESC LIMIT #{dto.pageSize} OFFSET #{dto.offset}

SELECT COUNT(DISTINCT n.id)
FROM notice n
LEFT JOIN notice_scope ns ON n.id = ns.notice_id
LEFT JOIN notice_read nr ON n.id = nr.notice_id AND nr.user_id = #{userId}
WHERE n.is_deleted = 0

    AND n.status = 'PUBLISHED'
    AND n.publish_time <= NOW()
    AND (n.expire_time IS NULL OR n.expire_time >= NOW())


    AND (n.title LIKE CONCAT('%', #{dto.keyword}, '%') OR n.content LIKE CONCAT('%', #{dto.keyword}, '%'))


    AND n.notice_type = #{dto.noticeType}


    AND n.priority = #{dto.priority}


    AND COALESCE(nr.read_status, 0) = #{dto.readStatus}

AND (
    ns.scope_type = 'ALL'
    OR ns.scope_type = 'USER' AND ns.scope_id = #{userId}
    OR ns.scope_type = 'DEPT' AND ns.scope_id = #{deptId}
)

SELECT n.id, n.title, n.notice_type as noticeType, n.priority, n.publisher_id as publisherId, n.publisher_name as publisherName, n.publish_time as publishTime, n.status, n.read_count as readCount, n.view_count as viewCount, CASE WHEN n.read_count = 0 THEN 0 ELSE ROUND(n.read_count * 100.0 / #{totalActiveUsers}, 2) END as readRate, n.created_at as createdAt FROM notice n WHERE n.is_deleted = 0
AND (n.title LIKE CONCAT('%', #{dto.keyword}, '%') OR n.content LIKE CONCAT('%', #{dto.keyword}, '%'))
AND n.status = #{dto.status}
AND n.publisher_id = #{dto.publisherId}
AND n.publish_time >= #{dto.startDate}
AND n.publish_time <= #{dto.endDate}
ORDER BY n.publish_time DESC LIMIT #{dto.pageSize} OFFSET #{dto.offset}

SELECT COUNT(*)
FROM notice n
WHERE n.is_deleted = 0

    AND (n.title LIKE CONCAT('%', #{dto.keyword}, '%') OR n.content LIKE CONCAT('%', #{dto.keyword}, '%'))


    AND n.status = #{dto.status}


    AND n.publisher_id = #{dto.publisherId}


    AND n.publish_time >= #{dto.startDate}


    AND n.publish_time <= #{dto.endDate}

